package com.formfiller.data

import androidx.room.*

@Entity(tableName = "profiles")
data class Profile(
    @PrimaryKey(autoGenerate = true) val id: Long = 0,
    val name: String,
    val createdAt: Long = System.currentTimeMillis()
)

@Entity(
    tableName = "fields",
    foreignKeys = [ForeignKey(
        entity = Profile::class,
        parentColumns = ["id"],
        childColumns = ["profileId"],
        onDelete = ForeignKey.CASCADE
    )],
    indices = [Index("profileId")]
)
data class Field(
    @PrimaryKey(autoGenerate = true) val id: Long = 0,
    val profileId: Long,
    val label: String,
    val value: String,
    val fieldType: String = "text" // name, id_number, phone, address, company, text
)

package com.formfiller.data

import androidx.room.*

@Dao
interface ProfileDao {
    @Query("SELECT * FROM profiles ORDER BY createdAt DESC")
    suspend fun getAll(): List<Profile>

    @Insert
    suspend fun insert(profile: Profile): Long

    @Delete
    suspend fun delete(profile: Profile)

    @Update
    suspend fun update(profile: Profile)
}

@Dao
interface FieldDao {
    @Query("SELECT * FROM fields WHERE profileId = :profileId")
    suspend fun getByProfile(profileId: Long): List<Field>

    @Query("SELECT * FROM fields")
    fun getAllSync(): List<Field>

    @Query("SELECT * FROM fields WHERE profileId = :profileId")
    fun getByProfileSync(profileId: Long): List<Field>

    @Insert
    suspend fun insert(field: Field): Long

    @Insert
    suspend fun insertAll(fields: List<Field>)

    @Delete
    suspend fun delete(field: Field)

    @Update
    suspend fun update(field: Field)

    @Query("DELETE FROM fields WHERE profileId = :profileId")
    suspend fun deleteByProfile(profileId: Long)
}

package com.formfiller.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase

@Database(entities = [Profile::class, Field::class], version = 1)
abstract class AppDatabase : RoomDatabase() {
    abstract fun profileDao(): ProfileDao
    abstract fun fieldDao(): FieldDao

    companion object {
        @Volatile private var instance: AppDatabase? = null

        fun get(context: Context): AppDatabase =
            instance ?: synchronized(this) {
                instance ?: Room.databaseBuilder(
                    context.applicationContext, AppDatabase::class.java, "formfiller.db"
                ).allowMainThreadQueries().build().also { instance = it }
            }
    }
}

