        view.findViewById<ImageButton>(R.id.btnSwitchKeyboard).setOnClickListener {
            (getSystemService(INPUT_METHOD_SERVICE) as InputMethodManager).showInputMethodPicker()
        }
        btnExpand.setOnClickListener { toggleExpand() }

        loadProfiles()
        return view
    }

    override fun onStartInputView(info: EditorInfo?, restarting: Boolean) {
        super.onStartInputView(info, restarting)
        loadProfiles()
        val hint = info?.hintText?.toString() ?: info?.label?.toString()
        showMatchedFields(hint)
    }

    private fun loadProfiles() {
        profiles = db.profileDao().let {
            // 同步查询，IME 中允许
            db.query("SELECT * FROM profiles ORDER BY createdAt DESC", null).use { cursor ->
                val list = mutableListOf<Profile>()
                while (cursor.moveToNext()) {
                    list.add(Profile(
                        id = cursor.getLong(cursor.getColumnIndexOrThrow("id")),
                        name = cursor.getString(cursor.getColumnIndexOrThrow("name")),
                        createdAt = cursor.getLong(cursor.getColumnIndexOrThrow("createdAt"))
                    ))
                }
                list
            }
        }
        if (profiles.isEmpty()) {
            tvProfile.text = "无档案"
            allFields = emptyList()
            tvHint.text = "请在主应用中导入文档"
        } else {
            if (currentProfileIndex >= profiles.size) currentProfileIndex = 0
            val p = profiles[currentProfileIndex]
            tvProfile.text = p.name
            allFields = db.fieldDao().getByProfileSync(p.id)
            tvHint.text = "${allFields.size} 个字段"
        }
    }

    private fun showMatchedFields(hint: String?) {
        val matched = FieldMatcher.match(hint, allFields)
        val adapter = FieldChipAdapter(matched) { field -> commitField(field) }
        rvFields.adapter = adapter
        rvAllFields.adapter = FieldChipAdapter(allFields) { field -> commitField(field) }
    }

    private fun commitField(field: Field) {
        currentInputConnection?.commitText(field.value, 1)
    }

    private fun switchProfile(delta: Int) {
        if (profiles.isEmpty()) return
        currentProfileIndex = (currentProfileIndex + delta + profiles.size) % profiles.size
        val p = profiles[currentProfileIndex]
        tvProfile.text = p.name
        allFields = db.fieldDao().getByProfileSync(p.id)
        tvHint.text = "${allFields.size} 个字段"
        showMatchedFields(currentInputEditorInfo?.hintText?.toString())
    }

    private fun toggleExpand() {
        expanded = !expanded
        rvAllFields.visibility = if (expanded) View.VISIBLE else View.GONE
        btnExpand.text = if (expanded) "收起 ▼" else "展开 ▲"
    }
}

package com.formfiller.ime

import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import android.widget.TextView
import androidx.recyclerview.widget.RecyclerView
import com.formfiller.R
import com.formfiller.data.Field

class FieldChipAdapter(
    private val fields: List<Field>,
    private val onClick: (Field) -> Unit
) : RecyclerView.Adapter<FieldChipAdapter.VH>() {

    class VH(view: View) : RecyclerView.ViewHolder(view) {
        val tv: TextView = view.findViewById(R.id.tvChip)
    }

    override fun onCreateViewHolder(parent: ViewGroup, viewType: Int) =
        VH(LayoutInflater.from(parent.context).inflate(R.layout.item_field_chip, parent, false))

    override fun onBindViewHolder(holder: VH, position: Int) {
        val f = fields[position]
        holder.tv.text = "${f.label}: ${f.value}"
        holder.tv.setOnClickListener { onClick(f) }
    }

    override fun getItemCount() = fields.size
}

