/**
 * 从文本中提取法律文书常见字段（姓名、身份证、电话、地址、公司）
 */
object FieldExtractor {

    data class ExtractedField(val label: String, val value: String, val type: String)

    private val patterns = listOf(
        Triple("身份证号", """(?:身份证[号码]*|证件号[码]*)[：:\s]*(\d{17}[\dXx])""", "id_number"),
        Triple("身份证号", """(?<!\d)\d{17}[\dXx](?!\d)""", "id_number"),
        Triple("手机号", """(?:手机|电话|联系方式|联系电话|移动电话)[：:\s]*(1[3-9]\d{9})""", "phone"),
        Triple("手机号", """(?<!\d)1[3-9]\d{9}(?!\d)""", "phone"),
        Triple("固定电话", """(?<!\d)(0\d{2,3}-?\d{7,8})(?!\d)""", "phone"),
        Triple("邮编", """(?:邮[政编][编码]*)[：:\s]*(\d{6})""", "postal"),
        Triple("地址", """(?:住所地|地址|住址|住所)[：:\s]*([^\n，,。；;]{5,50})""", "address"),
        Triple("公司", """([\u4e00-\u9fa5]{2,20}(?:有限公司|股份有限公司|集团|事务所))""", "company"),
    )

    private val rolePatterns = listOf(
        """(?:原告|申请人)[：:\s（(]*([^\n，,。；;）)]{2,20})""",
        """(?:被告|被申请人)[：:\s（(]*([^\n，,。；;）)]{2,20})""",
        """(?:委托代理人|代理人)[：:\s（(]*([^\n，,。；;）)]{2,20})""",
        """(?:法定代表人)[：:\s（(]*([^\n，,。；;）)]{2,20})""",
    )

    private val roleLabels = listOf("原告", "被告", "委托代理人", "法定代表人")

    fun extract(text: String): List<ExtractedField> {
        val results = mutableListOf<ExtractedField>()
        val seen = mutableSetOf<String>()

